mapper.select:
SELECT TBU.ID, TBU.USER_EMAIL, TBU.USER_PASSWORD, TBU.USER_PROFILE, TBU.USER_NAME, TBU.USER_NICKNAME,
       TBSU.SOCIAL_USER_PROVIDER_ID, TBSU.SOCIAL_USER_PROVIDER, TBSU.USER_ID
FROM TBL_USER TBU
JOIN TBL_SOCIAL_USER TBSU ON TBU.ID = TBSU.USER_ID
WHERE TBU.USER_EMAIL = #{userEmail}
  AND TBSU.SOCIAL_USER_PROVIDER = #{socialUserProvider}

SELECT CASE WHEN COUNT(*) > 0 THEN 1 ELSE 0 END
FROM TBL_USER TBU
JOIN TBL_SOCIAL_USER TBSU ON TBU.ID = TBSU.USER_ID
WHERE TBU.USER_EMAIL = #{userEmail}
  AND TBSU.SOCIAL_USER_PROVIDER = #{socialUserProvider}

mapper.update:
UPDATE TBL_USER
SET USER_PROFILE = #{userProfile}
WHERE ID = #{id}
